/**
 * Notification model — core types for the notification system.
 *
 * Architecture: The notification system is event-driven. Domain events
 * (order:created, user:created, etc.) flow through the EventBus.
 * The NotificationService subscribes to these events, builds
 * NotificationPayloads, and dispatches them through NotificationAdapters
 * (email, webhook, in-app, etc.).
 *
 * Constraints:
 * - All notifications are dispatched through adapters implementing NotificationAdapter.
 * - New channels are added by implementing NotificationAdapter, not by modifying this file.
 * - NotificationType enumerates the semantic kinds of notification, not delivery channels.
 */

/**
 * Semantic notification types — what the notification is about.
 * Extend this union as new notification triggers are added.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * Delivery channels — how the notification reaches the user.
 * Each channel corresponds to a NotificationAdapter implementation.
 */
export type NotificationChannel = 'email' | 'in_app' | 'webhook';

/**
 * The payload passed to NotificationAdapters for delivery.
 */
export interface NotificationPayload {
  /** Unique notification ID. */
  id: string;
  /** Semantic type of notification. */
  type: NotificationType;
  /** Delivery channel this payload targets. */
  channel: NotificationChannel;
  /** Recipient identifier (email address, user ID, webhook URL, etc.). */
  recipient: string;
  /** Notification subject / title. */
  subject: string;
  /** Notification body content. */
  body: string;
  /** Optional structured metadata for adapter-specific rendering. */
  metadata?: Record<string, unknown>;
  /** When the notification was created. */
  createdAt: Date;
}

/**
 * Result returned by a NotificationAdapter after attempting delivery.
 */
export interface NotificationResult {
  /** Whether delivery succeeded. */
  success: boolean;
  /** The channel that handled delivery. */
  channel: NotificationChannel;
  /** Error message if delivery failed. */
  error?: string;
  /** Timestamp of delivery attempt. */
  deliveredAt: Date;
}

/**
 * Stored notification record combining payload and delivery result.
 */
export interface NotificationRecord {
  payload: NotificationPayload;
  result: NotificationResult;
}

/**
 * NotificationAdapter interface — the contract all notification channel
 * implementations must satisfy.
 *
 * Architecture constraint: Every notification delivery channel (email,
 * webhook, in-app, SMS, etc.) MUST implement this interface and be
 * registered with the NotificationService via registerAdapter().
 *
 * The NotificationService dispatches NotificationPayloads to the adapter
 * whose channel matches payload.channel. Adapters are responsible for
 * the actual delivery mechanics.
 */

import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';

export interface NotificationAdapter {
  /** The channel this adapter handles. */
  readonly channel: NotificationChannel;

  /**
   * Send a notification through this channel.
   * Must not throw — return a failed NotificationResult instead.
   */
  send(payload: NotificationPayload): Promise<NotificationResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs sends in-memory rather than
 * connecting to a real SMTP server. The interface is real and must be
 * respected by any production replacement.
 *
 * Implements NotificationAdapter for the 'email' channel.
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationResult } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

export interface EmailMessage {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sentEmails: EmailMessage[] = [];

  /**
   * Send an email notification.
   * Stub: stores the email in-memory and returns success.
   */
  async send(payload: NotificationPayload): Promise<NotificationResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: EmailMessage = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);

    return {
      success: true,
      channel: this.channel,
      deliveredAt: new Date(),
    };
  }

  /**
   * Get all sent emails. Useful for testing.
   */
  getSentEmails(): EmailMessage[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history.
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

/**
 * Notification service — maps domain events to notification delivery.
 *
 * Architecture: This service subscribes to domain events via EventBus
 * and dispatches notifications through registered NotificationAdapters.
 * It does NOT use CallbackRegistry or any direct-call pattern.
 *
 * Constraints:
 * - All notifications go through EventBus → NotificationService → Adapter.
 * - New notification channels: implement NotificationAdapter, register via registerAdapter().
 * - New notification triggers: subscribe to the event in registerEventHandlers().
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent, UserCreatedEvent, UserUpdatedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type { NotificationChannel, NotificationPayload, NotificationRecord, NotificationType } from '../models/notification.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/** Reset the ID counter. Useful for testing. */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private adapters: Map<NotificationChannel, NotificationAdapter> = new Map();
  private records: NotificationRecord[] = [];

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Register a notification adapter for a delivery channel.
   * Only one adapter per channel is allowed; later registrations replace earlier ones.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registering adapter for channel: ${adapter.channel}`);
    this.adapters.set(adapter.channel, adapter);
  }

  /**
   * Subscribe to domain events that trigger notifications.
   * All event subscriptions live here — this is the single place
   * where domain events are mapped to notification logic.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });

    this.eventBus.on<UserCreatedEvent>('user:created', (event) => {
      return this.handleUserCreated(event);
    });

    this.eventBus.on<UserUpdatedEvent>('user:updated', (event) => {
      return this.handleUserUpdated(event);
    });
  }

  /**
   * Handle order created — send confirmation email.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    await this.dispatch({
      type: 'order_confirmation',
      channel: 'email',
      recipient: event.user.email,
      subject: `Order Confirmation: ${event.order.id}`,
      body: `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`,
    });
  }

  /**
   * Handle order status change — notify user of update.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    await this.dispatch({
      type: 'order_status_update',
      channel: 'email',
      recipient: event.order.userId,
      subject: `Order Update: ${event.order.id}`,
      body: `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`,
    });
  }

  /**
   * Handle user created — send welcome notification.
   */
  private async handleUserCreated(event: UserCreatedEvent): Promise<void> {
    await this.dispatch({
      type: 'welcome',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Welcome to TaskFlow Pro!',
      body: `Hi ${event.user.name}, welcome to TaskFlow Pro. Your account has been created.`,
    });
  }

  /**
   * Handle user updated — send account update notification.
   */
  private async handleUserUpdated(event: UserUpdatedEvent): Promise<void> {
    await this.dispatch({
      type: 'account_updated',
      channel: 'email',
      recipient: event.user.email,
      subject: 'Account Updated',
      body: `Your account has been updated. Changed fields: ${event.changes.join(', ')}.`,
    });
  }

  /**
   * Build a full payload and send it through the appropriate adapter.
   */
  private async dispatch(params: {
    type: NotificationType;
    channel: NotificationChannel;
    recipient: string;
    subject: string;
    body: string;
    metadata?: Record<string, unknown>;
  }): Promise<void> {
    const payload: NotificationPayload = {
      id: generateNotificationId(),
      type: params.type,
      channel: params.channel,
      recipient: params.recipient,
      subject: params.subject,
      body: params.body,
      metadata: params.metadata,
      createdAt: new Date(),
    };

    const adapter = this.adapters.get(params.channel);
    if (!adapter) {
      this.logger.warn(`No adapter registered for channel: ${params.channel}`);
      this.records.push({
        payload,
        result: {
          success: false,
          channel: params.channel,
          error: `No adapter registered for channel: ${params.channel}`,
          deliveredAt: new Date(),
        },
      });
      return;
    }

    const result = await adapter.send(payload);
    this.records.push({ payload, result });
    this.logger.info(`Notification ${payload.id} dispatched via ${params.channel}: ${result.success ? 'success' : 'failed'}`);
  }

  /**
   * Get all notification records (payload + result).
   */
  getNotificationRecords(): NotificationRecord[] {
    return [...this.records];
  }

  /**
   * Get notification records for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): NotificationRecord[] {
    return this.records.filter((r) => r.payload.recipient === recipient);
  }

  /**
   * Get the count of sent notifications.
   */
  getNotificationCount(): number {
    return this.records.length;
  }

  /**
   * Clear all notification records (useful for testing).
   */
  clearNotifications(): void {
    this.records = [];
  }
}

